import React from "react";
import {
  Flex,
  Box,
  Input,
  IconButton,
  Text,
  InputGroup,
  InputLeftElement,
  useBreakpointValue,
  Avatar,
} from "@chakra-ui/react";
import { FaSearch, FaBars } from "react-icons/fa";
import { AiOutlineBell, AiOutlineQuestionCircle } from "react-icons/ai";
import { useNavigate } from "react-router-dom";
import { useDisclosure } from "@chakra-ui/react";
import { useSelector } from "react-redux";

// nếu có
// import Dropdown from "./Dropdown";
// import { NavBarDrawer } from "../NavBarDrawer";

const TeacherNavTop = ({ handleSearch }) => {
  const isMobile = useBreakpointValue({ base: true, lg: false });
  const navigate = useNavigate();
  const { isOpen, onOpen, onClose } = useDisclosure();

  const userStore = useSelector((store) => store.UserReducer);

  return (
    <>
      <Flex
        as="nav"
        align="center"
        justify="space-between"
        px={6}
        py={3}
        bg="#ffffff"
        borderBottom="1px solid #e5e7eb"
        position="fixed"
        top="0"
        left="0"
        right="0"
        zIndex="1000"
      >
        {/* LEFT: Logo */}
        <Text
          fontSize="2xl"
          fontWeight="bold"
          color="#A435F0"
          cursor="pointer"
          onClick={() => navigate("/home")}
          >
            SRM
        </Text>

        {/* CENTER: Search */}
        {!isMobile && (
          <Box flex="1" mx={8}>
            <InputGroup>
              <InputLeftElement pointerEvents="none">
                <FaSearch color="gray" />
              </InputLeftElement>

              <Input
                placeholder="Search courses..."
                borderRadius="999px"
                bg="#f7f9fa"
                _focus={{
                  borderColor: "#A435F0",
                  boxShadow: "0 0 0 1px #A435F0",
                }}
                onChange={(e) => handleSearch?.(e.target.value)}
              />
            </InputGroup>
          </Box>
        )}

        {/* RIGHT */}
        {/* RIGHT */}
        {!isMobile ? (
          <Flex align="center" gap={4}>
            {user?.role !== "teacher" && user?.role !== "admin" && (
              <Text
                cursor="pointer"
                _hover={{ color: "#A435F0" }}
                onClick={() => navigate("/Teachme")}
              >
                Teach on SRM
              </Text>
            )}

            <Dropdown />
          </Flex>
        ) : (
          <IconButton
            aria-label="Menu"
            icon={<FaBars />}
            variant="ghost"
            fontSize="xl"
            onClick={onOpen}
          />
        )}
      </Flex>

      {/* Drawer Mobile */}
      <NavBarDrawer isOpen={isOpen} onOpen={onOpen} onClose={onClose} />
    </>
  );
};

export default TeacherNavTop;
